import{_ as a,c as i,o as d,ah as s}from"./chunks/framework.C-x9UAyH.js";const g=JSON.parse('{"title":"Regiones y Zonas de disponibilidad","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/regiones_zonas.md","filePath":"aws/regiones_zonas.md","lastUpdated":1760459112000}'),n={name:"aws/regiones_zonas.md"};function o(r,e,t,l,p,c){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="regiones-y-zonas-de-disponibilidad" tabindex="-1">Regiones y Zonas de disponibilidad <a class="header-anchor" href="#regiones-y-zonas-de-disponibilidad" aria-label="Permalink to &quot;Regiones y Zonas de disponibilidad&quot;">​</a></h1><p>Las regiones y zonas de disponibilidad forman parte de la infraestructura global de AWS, es decir, la base sobre la que se ejecutan los servicios y productos de AWS.</p><h2 id="regiones-de-aws" tabindex="-1">Regiones de AWS <a class="header-anchor" href="#regiones-de-aws" aria-label="Permalink to &quot;Regiones de AWS&quot;">​</a></h2><p>Las regiones de AWS se identifican con un código de región de dos letras, por ejemplo, us-east-1 para la región Este de EE. UU. (Norte de Virginia). Cada región tiene su propia infraestructura, que incluye centros de datos, redes, almacenamiento y servicios.</p><p>Las regiones de AWS están disponibles en todo el mundo, incluidas América del Norte, América del Sur, Europa, Oriente Medio y África, Asia y Oceanía.</p><h2 id="zonas-de-disponibilidad" tabindex="-1">Zonas de disponibilidad <a class="header-anchor" href="#zonas-de-disponibilidad" aria-label="Permalink to &quot;Zonas de disponibilidad&quot;">​</a></h2><p>Las zonas de disponibilidad se identifican con un código de zona de dos letras, por ejemplo, us-east-1a para la zona de disponibilidad a de la región Este de EE. UU. (Norte de Virginia).</p><p>Cada zona de disponibilidad está ubicada en una instalación física diferente dentro de una región. Las zonas de disponibilidad están diseñadas para estar aisladas entre sí, lo que proporciona redundancia y resistencia a los fallos. Por ejemplo, si un desastre natural o un corte de energía afecta a una zona de disponibilidad, los recursos de la otra zona de disponibilidad seguirán estando disponibles.</p>',8)])])}const b=a(n,[["render",o]]);export{g as __pageData,b as default};
